mapper.select:
SELECT S.STFF_ID, S.STFF_NM, S.STFF_ENG_NM, S.STFF_TYPE_CD, C.CD_NM AS STFF_TYPE_NM, S.STFF_NTNLT, S.STFF_FRGN_YN, S.STFF_BRTH_DT, S.STFF_EXP_YR, S.STFF_ANSL_SAL, S.STFF_STTS_CD, T.TM_ID, T.TM_KR_NM FROM STFF S LEFT JOIN CMN_CD C ON C.CD_ID = 'STFF_TYPE' AND C.CD_VAL = S.STFF_TYPE_CD LEFT JOIN TM T ON T.TM_ID = S.TM_ID
AND S.STFF_STTS_CD = 'AT' AND S.TM_ID = #{tmId} AND S.STFF_TYPE_CD = #{stffTypeCd}
ORDER BY S.TM_ID, S.STFF_TYPE_CD, S.STFF_ID
